def get_db_connection():
    client = secretmanager.SecretManagerServiceClient()
    project_id = os.environ.get('GCP_PROJECT')
    
    secret_name = f"projects/{project_id}/secrets/db-password/versions/latest"
    response = client.access_secret_version(request={"name": secret_name})
    db_password = response.payload.data.decode('UTF-8')
    
    connection = pymysql.connect(
        host=os.environ.get('DB_HOST'),
        user=os.environ.get('DB_USER'),
        password=db_password,
        database=os.environ.get('DB_NAME'),
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=5
    )
    return connection

def validate_column_name(column):
    allowed_columns = {
        'id', 'name', 'email', 'status', 'category', 
        'created_at', 'updated_at', 'price', 'quantity',
        'description', 'title', 'user_id', 'product_id'
    }
    return column in allowed_columns

def validate_operator(operator):
    allowed_operators = {'=', '>', '<', '>=', '<=', '!=', 'LIKE', 'IN'}
    return operator.upper() in allowed_operators

def sanitize_value(value, operator):
    if operator.upper() == 'IN':
        if isinstance(value, str):
            values = [v.strip() for v in value.split(',')]
        else:
            values = value
        return values
    return value

def build_where_clause(filters):
    if not filters:
        return "", []
    
    conditions = []
    params = []
    
    for filter_item in filters:
        column = filter_item.get('column')
        operator = filter_item.get('operator', '=')
        value = filter_item.get('value')
        
        if not column or value is None:
            continue
            
        if not validate_column_name(column):
            raise ValueError(f"Invalid column name: {column}")
        
        if not validate_operator(operator):
            raise ValueError(f"Invalid operator: {operator}")
        
        sanitized_value = sanitize_value(value, operator)
        
        if operator.upper() == 'LIKE':
            conditions.append(f"{column} LIKE %s")
            params.append(f"%{sanitized_value}%")
        elif operator.upper() == 'IN':
            placeholders = ','.join(['%s'] * len(sanitized_value))
            conditions.append(f"{column} IN ({placeholders})")
            params.extend(sanitized_value)
        else:
            conditions.append(f"{column} {operator} %s")
            params.append(sanitized_value)
    
    where_clause = " AND ".join(conditions) if conditions else ""
    return where_clause, params

def validate_order_by(order_by):
    if not order_by:
        return None
    
    column = order_by.get('column')
    direction = order_by.get('direction', 'ASC').upper()
    
    if not validate_column_name(column):
        raise ValueError(f"Invalid order by column: {column}")
    
    if direction not in ('ASC', 'DESC'):
        raise ValueError(f"Invalid sort direction: {direction}")
    
    return f"{column} {direction}"

def validate_limit(limit):
    if limit is None:
        return 100
    
    try:
        limit_int = int(limit)
        if limit_int < 1 or limit_int > 1000:
            return 100
        return limit_int
    except (ValueError, TypeError):
        return 100

def validate_offset(offset):
    if offset is None:
        return 0
    
    try:
        offset_int = int(offset)
        if offset_int < 0:
            return 0
        return offset_int
    except (ValueError, TypeError):
        return 0

def verify_api_key(request):
    api_key = request.headers.get('X-API-Key')
    if not api_key:
        return False
    
    expected_key = os.environ.get('API_KEY_HASH')
    if not expected_key:
        return False
    
    key_hash = hashlib.sha256(api_key.encode()).hexdigest()
    return hmac.compare_digest(key_hash, expected_key)

